<script setup lang="ts">import{onMounted,ref,watch}from"vue";import{useRoute}from"vue-router";import{Search,ChevronDown}from"lucide-vue-next";import{api,type Department,type Doctor}from"../api";import PageHeader from"../components/PageHeader.vue";import DoctorCard from"../components/DoctorCard.vue";const doctors=ref<Doctor[]>([]),departments=ref<Department[]>([]),keyword=ref(String(useRoute().query.keyword??"")),departmentId=ref<number>();async function load(){doctors.value=await api.doctors({keyword:keyword.value,departmentId:departmentId.value})};onMounted(async()=>{departments.value=await api.departments();await load()});let timer:number;watch([keyword,departmentId],()=>{clearTimeout(timer);timer=window.setTimeout(load,250)});</script><template><main><PageHeader title="找医生"/><div class="search-box"><Search/><input v-model="keyword" placeholder="搜医院、医生、疾病"/></div><div class="filters"><button>北京市<ChevronDown/></button><select v-model="departmentId"><option :value="undefined">全部科室</option><option v-for="d in departments" :value="d.id">{{d.name}}</option></select><button>疾病<ChevronDown/></button></div><section class="doctor-results"><DoctorCard v-for="d in doctors" :key="d.id" :doctor="d"/><div v-if="!doctors.length" class="empty">没有找到相关医生</div></section></main></template>
